// Schedule path: combine Operating Bible + raw KG opportunities into scoring prompt
const bibleNode = $('Read Operating Bible (Schedule)');
const rawOppsNode = $('Fetch Raw Opportunities (KG)');

let bible = '';
try {
  bible = bibleNode.first().json.content || '';
} catch (e) {
  bible = '(Operating Bible not available)';
}

let rawOpps = [];
try {
  rawOpps = rawOppsNode.all().map(item => item.json);
  // If the HTTP request returned an array in the response body
  if (rawOpps.length === 1 && Array.isArray(rawOpps[0])) {
    rawOpps = rawOpps[0];
  }
} catch (e) {
  rawOpps = [];
}

// Extract scoring criteria sections from the bible
const partII = bible.match(/# Part II:.*?(?=# Part III:)/s)?.[0] || '';
const partVIII = bible.match(/# Part VIII:.*?(?=# Part IX:)/s)?.[0] || '';

let rawOppsText = '';
if (rawOpps.length > 0) {
  rawOppsText = '\n\n## Raw Opportunities from Knowledge Graph (last 24h)\nScore each of these:\n\n';
  for (const opp of rawOpps) {
    rawOppsText += `- **${opp.category || 'Unknown'}** (${opp.source_tier || 'unknown tier'}): ${opp.description || 'No description'}\n  Source: ${opp.source_url || 'N/A'} | Est. keyword volume: ${opp.estimated_keyword_volume || 'N/A'} | Competition: ${opp.competition_level || 'N/A'}\n\n`;
  }
} else {
  rawOppsText = '\n\n## No raw opportunities found in Knowledge Graph. Generate 5-10 new ideas from market research.\n';
}

const opportunities = rawOpps.map(o => ({
  id: o.id,
  category: o.category,
  source_tier: o.source_tier
}));

return [{
  json: {
    trigger_type: 'schedule',
    raw_opportunity_ids: opportunities,
    prompt: `Today is ${new Date().toISOString().split('T')[0]}. You are the Discovery Engine for The Forge (Forge Technologies).

Your job: score business opportunities across all five sourcing tiers.

## What We Build (from Operating Bible)
${partII}

## How We Find Ideas (from Operating Bible)
${partVIII}
${rawOppsText}
## Business Types
We build BOTH traditional SMB SaaS (scheduling, CRM, invoicing for local businesses) AND AI SaaS products (AI-powered tools for professionals like lawyers, accountants, recruiters, marketers). AI SaaS products use usage-based pricing and can command higher margins.

## Scoring Dimensions (Part III - Bible v10)
For EACH opportunity, provide scores on these 10 dimensions (1-10 each):
1. **Demand Evidence** (1-10): Keyword volume, search trends, existing competitors with revenue
2. **Feasibility for AI Build** (1-10): Can Claude Code build this? Standard SaaS patterns?
3. **Monetization Clarity** (1-10): Will they pay? How much? Clear value prop?
4. **Competition Gap** (1-10): Are incumbents weak or strong? Bad UX/reviews? Fragmented market?
5. **Distribution Viability** (1-10): Can we reach buyers via cold email/calls? SEO opportunity?
6. **Data Lock-In Potential** (1-10): Will customers get stuck? Does data accumulate value over time?
7. **AI Enhancement Potential** (1-10): Can AI make this 10x better than manual? Is there a learning loop?
8. **Revenue Ceiling** (1-10): Can this reach $100K MRR? Show math.
9. **Time to Revenue** (1-10): How fast to first paying customer? Under 30 days = 10, over 90 days = 3.
10. **Vertical Scalability** (1-10): Can we build multiple products in this vertical?
11. **Overall Score**: Average of above 10 dimensions. THRESHOLD: 6.5+ to pass.

For each opportunity also provide:
- **Name/Concept**: Brief description
- **Category**: e.g. pet_grooming_scheduling, hvac_dispatch, ai_legal, ai_recruiting, etc.
- **Sourcing Tier**: tier1_clone | tier2_smb | tier3_platform | tier4_keyword | tier5_support
- **Target Market**: Who buys, TAM estimate
- **Revenue Ceiling Test**: Can this reach $100K MRR? Show math.
- **Scoring Notes**: Why each dimension got its score

Only include opportunities scoring 6.5+ overall.

Output as JSON array:
[
  {
    "name": "...",
    "category": "...",
    "source_tier": "...",
    "target_market": "...",
    "revenue_ceiling_test": "...",
    "demand_evidence": 8,
    "feasibility_ai_build": 7,
    "monetization_clarity": 9,
    "competition_gap": 6,
    "distribution_viability": 7,
    "data_lockin_potential": 8,
    "ai_enhancement_potential": 9,
    "revenue_ceiling": 7,
    "time_to_revenue": 8,
    "vertical_scalability": 7,
    "overall_score": 7.6,
    "scoring_notes": "..."
  }
]

Return ONLY the JSON array, no other text.`
  }
}];

// Webhook path: build scoring prompt from Huginn signal payload
