const sourceTier = signal.source_tier || 'unknown';
const sourceUrl = signal.source_url || 'N/A';
const category = signal.category || 'unknown';
const description = signal.description || 'No description provided';
const keywordVolume = signal.estimated_keyword_volume || 'N/A';
const competition = signal.competition_level || 'N/A';
const rawData = JSON.stringify(signal.raw_data || {}, null, 2);

return [{
  json: {
    trigger_type: 'webhook',
    signal: signal,
    prompt: `Today is ${new Date().toISOString().split('T')[0]}. You are the Discovery Engine for The Forge (Forge Technologies).

A real-time signal has arrived from Huginn. Score this opportunity.

## Incoming Signal
- **Source Tier**: ${sourceTier}
