// Parse the LLM JSON response and decide next steps
const llmOutput = $('Discovery LLM Chain').first().json.text || '';

let opportunities = [];
try {
  // Try to parse JSON from the response (handle possible markdown fencing)
  let jsonStr = llmOutput;
  const fenced = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenced) jsonStr = fenced[1];
  opportunities = JSON.parse(jsonStr.trim());
} catch (e) {
  // If parsing fails, wrap the raw text as a single entry
  opportunities = [{
    name: 'Parse Error - Raw Output',
    category: 'unknown',
    source_tier: 'unknown',
    overall_score: 0,
    scoring_notes: llmOutput,
    demand_evidence: 0,
    feasibility_ai_build: 0,
    monetization_clarity: 0,
    competition_gap: 0,
    distribution_viability: 0
  }];
}

// Determine trigger type from upstream
let triggerType = 'schedule';
try {
  triggerType = $('Build Prompt (Webhook Path)').first().json.trigger_type;
} catch (e) {
  try {
    triggerType = $('Build Prompt (Schedule Path)').first().json.trigger_type;
  } catch (e2) {
    triggerType = 'schedule';
  }
}

const timestamp = new Date().toISOString();

// Build markdown report
let report = `# Discovery Engine Report - ${timestamp.split('T')[0]}\n`;
report += `Trigger: ${triggerType}\n\n`;

const highScorers = [];

for (const opp of opportunities) {
  const score = opp.overall_score || 0;
  const passed = score >= 6.5 ? 'PASS' : 'FAIL';
  report += `## ${opp.name} [${passed}] (Score: ${score})\n`;
  report += `- Category: ${opp.category}\n`;
  report += `- Source Tier: ${opp.source_tier}\n`;
  report += `- Demand Evidence: ${opp.demand_evidence}/10\n`;
  report += `- Feasibility (AI Build): ${opp.feasibility_ai_build}/10\n`;
  report += `- Monetization Clarity: ${opp.monetization_clarity}/10\n`;
  report += `- Competition Gap: ${opp.competition_gap}/10\n`;
  report += `- Distribution Viability: ${opp.distribution_viability}/10\n`;
  report += `- Data Lock-In Potential: ${opp.data_lockin_potential || 'N/A'}/10\n`;
  report += `- AI Enhancement Potential: ${opp.ai_enhancement_potential || 'N/A'}/10\n`;
  report += `- Revenue Ceiling: ${opp.revenue_ceiling || 'N/A'}/10\n`;
  report += `- Time to Revenue: ${opp.time_to_revenue || 'N/A'}/10\n`;
  report += `- Vertical Scalability: ${opp.vertical_scalability || 'N/A'}/10\n`;
  report += `- Target Market: ${opp.target_market || 'N/A'}\n`;
  report += `- Revenue Ceiling: ${opp.revenue_ceiling_test || 'N/A'}\n`;
  report += `- Notes: ${opp.scoring_notes || 'N/A'}\n\n`;

  if (score >= 6.5) {
    highScorers.push(opp);
  }
}

return [{
  json: {
    trigger_type: triggerType,
    timestamp: timestamp,
    report: report,
    opportunities: opportunities,
    high_scorers: highScorers,
    has_high_scorers: highScorers.length > 0
  }
}];

// Build Supabase query to fetch post-mortems for categories of high-scoring opportunities
const highScorers = $('Parse Scores & Build Report').first().json.high_scorers;
const categories = [...new Set(highScorers.map(o => o.category).filter(Boolean))];

// Build OR filter for categories
const categoryFilter = categories.map(c => `category.eq.${c}`).join(',');

return [{
  json: {
    categories: categories,
    category_filter: categoryFilter,
    high_scorers: highScorers
  }
}];

// Enrich high-scoring opportunities with post-mortem context
const postMortems = $('Fetch Related Post-Mortems').all().map(item => item.json);
const highScorers = $('Prepare Post-Mortem Query').first().json.high_scorers;

let pmData = postMortems;
// Handle case where response is an array wrapped in a single item
if (pmData.length === 1 && Array.isArray(pmData[0])) {
  pmData = pmData[0];
}

// Build enrichment notes per high scorer
const enriched = highScorers.map(opp => {
  const relatedPMs = pmData.filter(pm => pm.category === opp.category);
  let pmNotes = '';
  if (relatedPMs.length > 0) {
    pmNotes = '\n### Related Post-Mortems:\n';
    for (const pm of relatedPMs) {
      pmNotes += `- **${pm.title || pm.name || 'Untitled'}**: ${pm.lessons_learned || pm.summary || 'No summary'}\n`;
    }
  } else {
    pmNotes = '\nNo related post-mortems found for this category.';
  }
  return {
    ...opp,
    post_mortem_context: pmNotes
  };
});

// Update KG with post-mortem enrichment notes
const updatePayloads = enriched.map(opp => ({
  category: opp.category,
  name: opp.name,
  post_mortem_context: opp.post_mortem_context
}));

return [{
  json: {
    enriched_opportunities: enriched,
    update_payloads: updatePayloads,
    summary: `Enriched ${enriched.length} high-scoring opportunities with ${pmData.length} related post-mortems.`
  }
}];

const enriched = $('Enrich with Post-Mortem Context').first().json.enriched_opportunities;

// Build one output item per high-scoring opportunity for individual Telegram notifications
return enriched.map(opp => {
  const businessId = (opp.category || opp.name || 'unknown')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 40);

  const businessName = (opp.name || 'Unnamed').substring(0, 60);
  const category = opp.category || 'unknown';

  const message = `\u2b50 *High-Scoring Opportunity*\n\n` +
    `*${opp.name}*\n` +
    `Score: *${opp.overall_score}/10*\n` +
    `Category: ${category}\n` +
    `Source Tier: ${opp.source_tier}\n\n` +
    `Demand: ${opp.demand_evidence}/10 | Feasibility: ${opp.feasibility_ai_build}/10\n` +
    `Monetization: ${opp.monetization_clarity}/10 | Gap: ${opp.competition_gap}/10\n` +
    `Distribution: ${opp.distribution_viability}/10\n\n` +
    `Target: ${opp.target_market || 'N/A'}\n` +
    `Revenue Ceiling: ${opp.revenue_ceiling_test || 'N/A'}\n` +
    `${opp.post_mortem_context || ''}\n\n` +
    `_Tap Approve to trigger the full creation pipeline._`;

  // callback_data: decision|agent|businessId|businessName|description
  const businessDescription = (opp.scoring_notes || '').substring(0, 100);
  const approveData = `approve|Discovery Engine|${businessId}|${businessName}|${businessDescription}`;
  const rejectData = `reject|Discovery Engine|${businessId}|${businessName}|${businessDescription}`;

  return {
    json: {
      message,
      businessId,
      businessName,
      category,
      approveData,
      rejectData
    }
  };
});

const opp = $json;
const score = parseFloat(opp.message.match(/Score: \*(\d+\.?\d*)/)?.[1] || '0');

// Auto-approve above 8.0, manual review 7.0-8.0, auto-reject below 7.0
if (score >= 8.0) {
  return [{ json: { ...opp, _autoApprove: true, _score: score } }];
} else if (score >= 7.0) {
  return [{ json: { ...opp, _autoApprove: false, _manualReview: true, _score: score } }];
} else {
  return [{ json: { ...opp, _autoApprove: false, _manualReview: false, _autoReject: true, _score: score } }];
}
